    acc1.deposit(-100.0);
    oss << "Account " << acc1.getAccountNumber() << " after deposit -100: " << acc1.getBalance() << std::endl;
    acc1.withdraw(-50.0);
    oss << "Account " << acc1.getAccountNumber() << " after withdraw -50: " << acc1.getBalance() << std::endl;
    BankAccount acc2("ACC002");
