    acc2.deposit(250.0);
    oss << "Account " << acc2.getAccountNumber() << " after deposit 250: " << acc2.getBalance() << std::endl;
    acc2.withdraw(250.0);
    oss << "Account " << acc2.getAccountNumber() << " after withdraw 250: " << acc2.getBalance() << std::endl;
    acc2.withdraw(1.0);
